internal final class ETGCustInvoiceOpenTransController extends SrsReportRunController
{
}

Method.Source:
/// <summary>
/// Class entry point. The system will call this method when a designated menu 
/// is selected or when execution starts and this class is set as the startup class.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static ETGCustInvoiceOpenTransController construct()
{
    return new ETGCustInvoiceOpenTransController();
}

public static void main(Args _args)
{
    ETGCustInvoiceOpenTransController controller    = new ETGCustInvoiceOpenTransController();
    ETGCanadaParameters canadaParameters            = ETGCanadaParameters::find();

    if(canadaParameters.ETGARNotifications == NoYes::Yes)
    {
        controller.parmReportName(ssrsReportStr(ETGCustInvoiceOpenTransReport, Report));
        controller.parmArgs(_args);
        controller.parmDialogCaption("@ETGInvoiceDueNotification:ETGIDN008");
        controller.startOperation();
    }

    else
    {
        warning("@ETGInvoiceDueNotification:ETGIDN012");
    }
}
